{
  description = "Smart Contract Audit Swarm Environment";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
  };

  outputs = { self, nixpkgs }:
  let
    system = "x86_64-linux";
    pkgs = import nixpkgs { inherit system; };
  in {
    devShells.${system}.default = pkgs.mkShell {
      buildInputs = with pkgs; [
        python311
        python311Packages.pip
        python311Packages.virtualenv
        solc # Solc is required by Slither to compile contracts during analysis
      ];

      shellHook = ''
        if [ ! -d .venv ]; then
          python -m venv .venv
          source .venv/bin/activate
          # Slither is now handled by pip to bypass the Nixpkgs Sphinx breakage
          pip install slither-analyzer crewai langchain-community
        else
          source .venv/bin/activate
        fi
        echo "Audit Swarm Environment Active."
      '';
    };
  };
}

